noncompliant:
void processData() {
    int value = 42;
    std::string data = "test";

    auto lambda = [&]() {  // Noncompliant - captures all by reference
        return value + data.length();
    };

    std::async(std::launch::async, lambda);  // Risky: variables may be out of scope
}

compliant:
void processData() {
    int value = 42;
    std::string data = "test";

    auto lambda = [value, &data]() {  // Compliant - explicit capture
        return value + data.length();
    };

    // Or capture by value for safety
    auto safeLambda = [value, data]() {  // Compliant - explicit capture by value
        return value + data.length();
    };

    std::async(std::launch::async, safeLambda);
}
